#!/usr/bin/env python3
"""
Pre-launch checklist runner for AI feature launches.
Run this 24-48 hours before the launch window opens.
"""

import sys
import requests
import subprocess
from dataclasses import dataclass

@dataclass
class Check:
    name: str
    passed: bool
    detail: str

def check_status_page_configured() -> Check:
    """Verify the status page component exists and is accessible."""
    try:
        r = requests.get(
            "https://api.statuspage.io/v1/pages/{PAGE_ID}/components",
            headers={"Authorization": "OAuth {STATUSPAGE_TOKEN}"},
            timeout=5,
        )
        components = r.json()
        ai_components = [c for c in components if "ai" in c["name"].lower()]
        passed = len(ai_components) > 0
        return Check("Status page component", passed,
                     f"Found {len(ai_components)} AI component(s)")
    except Exception as e:
        return Check("Status page component", False, str(e))

def check_on_call_rotation() -> Check:
    """Verify on-call rotation is active in PagerDuty."""
    try:
        r = requests.get(
            "https://api.pagerduty.com/oncalls",
            params={"schedule_ids[]": "{AI_ONCALL_SCHEDULE_ID}"},
            headers={"Authorization": "Token token={PD_TOKEN}"},
            timeout=5,
        )
        oncalls = r.json().get("oncalls", [])
        passed = len(oncalls) > 0
        names = [o["user"]["name"] for o in oncalls]
        return Check("On-call rotation", passed,
                     f"On call: {", ".join(names) if names else "NOBODY"}")
    except Exception as e:
        return Check("On-call rotation", False, str(e))

def check_runbook_exists() -> Check:
    """Verify the launch runbook URL returns 200."""
    url = "https://wiki.internal/runbook/ai-feature-launch"
    try:
        r = requests.get(url, timeout=5)
        return Check("Runbook accessible", r.status_code == 200,
                     f"HTTP {r.status_code} at {url}")
    except Exception as e:
        return Check("Runbook accessible", False, str(e))

def check_feature_flag_enabled(percentage: float = 0.0) -> Check:
    """Verify feature flag is configured to roll out at the target percentage."""
    # Replace with your feature flag client
    import subprocess
    result = subprocess.run(
        ["ff", "get", "ai-assistant-v2"],
        capture_output=True, text=True
    )
    current = float(result.stdout.strip().split()[-1].replace("%", ""))
    passed = abs(current - percentage) < 0.01
    return Check("Feature flag", passed,
                 f"Current rollout: {current}%, expected: {percentage}%")

def run_checklist() -> bool:
    checks = [
        check_status_page_configured(),
        check_on_call_rotation(),
        check_runbook_exists(),
        check_feature_flag_enabled(percentage=0.0),
    ]
    all_passed = True
    for check in checks:
        status = "PASS" if check.passed else "FAIL"
        print(f"[{status}] {check.name}: {check.detail}")
        if not check.passed:
            all_passed = False
    return all_passed

if __name__ == "__main__":
    ok = run_checklist()
    print("\nAll checks passed — ready to launch!" if ok else "\nFix failures before launching.")
    sys.exit(0 if ok else 1)
